#!/usr/bin/env bash
# Self-contained: uploads the tender-note PDF to the coach material endpoint.
# Uses $BASE, $TOKEN, $CID from your shell (CID = the course id from your shelf call).
set -e
: "${BASE:?set BASE}"; : "${TOKEN:?set TOKEN}"; : "${CID:?set CID (your course id)}"
B64=''
echo "uploading (${#B64} b64 chars) → distilling (one-time Sonnet clerk, gives it a few seconds)…"
curl -s -X POST "$BASE/coach/$CID/material" -H "Authorization: Bearer $TOKEN" \
  -H "Content-Type: application/json" -d "{\"filename\":\"tender_note.pdf\",\"dataB64\":\"$B64\"}"; echo
echo "--- shelf ---"
curl -s "$BASE/coach/$CID/shelf" -H "Authorization: Bearer $TOKEN"; echo
